class MigrationRunner
{
    void ApplyMigrations(AppDbContext db)
    {
        // Fixed: EF Core 9 manages its own transactions and ExecutionStrategy
        // during Migrate(). Wrapping in a user transaction now throws.
        db.Database.Migrate();
    }
}

