using Microsoft.EntityFrameworkCore;

// =============================================================================
// Cosmos DB Breaking Changes in EF Core 9 — Required fixes for existing data
// =============================================================================
//
// These fixes apply to a separate Cosmos DB project that has existing documents
// written by EF Core 8. Apply these patterns to your Cosmos DbContext.

// EXAMPLE: Entity used with Cosmos DB provider
class Session
{
    public string Id { get; set; } = null!;
    public string Title { get; set; } = null!;
}

class CosmosDbContext : DbContext
{
    public DbSet<Session> Sessions => Set<Session>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // =====================================================================
        // FIX 1: Discriminator property renamed from "Discriminator" to "$type"
        // =====================================================================
        // EF Core 9 defaults to "$type" to align with System.Text.Json.
        // Existing documents use "Discriminator". Without this, queries against
        // existing documents will fail to match the discriminator value.
        modelBuilder.Entity<Session>().HasDiscriminator<string>("Discriminator");

        // =====================================================================
        // FIX 2: id property no longer contains the discriminator
        // =====================================================================
        // EF Core 8 stored ids as "Session|123". EF Core 9 stores just "123".
        // Without this, FindAsync and point-reads will fail on existing documents
        // because EF generates "123" but the stored document has "Session|123".
        modelBuilder.Entity<Session>().HasRootDiscriminatorInJsonId(true);
    }
}

// =============================================================================
// FIX 3: Synchronous Cosmos DB queries now throw
// =============================================================================
// The Cosmos DB provider no longer supports sync I/O. All synchronous calls
// (ToList, SaveChanges, First, Single, Count, etc.) must use async equivalents.
//
// BEFORE (throws InvalidOperationException in EF Core 9):
//   var sessions = db.Sessions.ToList();
//   db.SaveChanges();
//   var first = db.Sessions.First();
//
// AFTER:
//   var sessions = await db.Sessions.ToListAsync();
//   await db.SaveChangesAsync();
//   var first = await db.Sessions.FirstAsync();

